        <VerticalStackLayout
            Spacing="25"
            Padding="30,0"
            VerticalOptions="Center">
            <Label
                x:Name="currentUICulture"
                FontSize="Small" />
            <Label
                x:Name="seperatorChar"
                FontSize="Small" />
            <Entry
                Keyboard="Numeric" />
        </VerticalStackLayout>
    </ScrollView>
</ContentPage>
```

```
using System.Threading;

namespace NumericKeyboard
{
